var e=JSON.parse(`[{"id":"L3_1","type":"dialog","speaker":"SEO_YOON_ALT_CA_NULL","text":{"KOREA":"대체 병사를 얼마나 많이 끌고 온 거야? 가도 가도 끝이 없어!","JPN":"いったいどれだけたくさんの兵士を連れてきているの？　どこまで行っても終わりが見えないわ！","ENG":"Just how many soldiers did they bring over? The wave is endless!","TWN":"到底帶來了多少士兵啊？怎麼沒完沒了！"},"stage":{"bg":"COUNTERSIDE_ASH","bgm":"BATTLE_BOSS_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SEO_YOON_ALT_CA_NULL","face":"UNIT_HATE"},"R":null}},"sfx":"FX_CUTSCEN_NOISE_RUSTLE_04"},{"id":"L4_1","type":"dialog","speaker":"JOOSHIYOON_FENRIR_CA_NULL","text":{"KOREA":"증원이 끊이질 않네요. 아무래도 저희 생각을 읽은 모양인데요.","JPN":"増援が絶えませんね。どうやらこちらの意図が読まれたようです。","ENG":"They keep sending in more troops. I think they read our minds.","TWN":"增援不斷啊。看來他們知道我們在想什麼。"},"stage":{"bg":"COUNTERSIDE_ASH","bgm":"BATTLE_BOSS_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"JOOSHIYOON_FENRIR_CA_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L7_1","type":"dialog","speaker":"JOOSHIYOON_FENRIR_CA_NULL","text":{"KOREA":"뭐, 가장 큰 문제는 이 분들이 모두 마왕의 힘으로 강해졌다는 점이겠지만요.","JPN":"まぁ、最も大きな問題はこの方々が全員、魔王の力によって強化されているという点ですけどね。","ENG":"Well, the biggest issue is that they've been heightened with the Demon Lord's power.","TWN":"嗯，最大的問題是他們全都是依靠魔王之力變強的吧？"},"stage":{"bg":"COUNTERSIDE_ASH","bgm":"BATTLE_BOSS_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SEO_YOON_ALT_CA_NULL","face":"UNIT_HATE"},"C":null,"R":{"char_id":"JOOSHIYOON_FENRIR_CA_NULL","face":"UNIT_IDLE"}}}},{"id":"L8_1","type":"dialog","speaker":"JOOSHIYOON_FENRIR_CA_NULL","text":{"KOREA":"하하, 이거 벌써부터 손목이 욱신거려서 큰일이네요.","JPN":"はは、もう手首が痛くなってきてしまいましたよ。","ENG":"Ha ha, my fingers are already starting to ache.","TWN":"哈哈，手腕已經開始痠了，這下可糟了。"},"stage":{"bg":"COUNTERSIDE_ASH","bgm":"BATTLE_BOSS_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SEO_YOON_ALT_CA_NULL","face":"UNIT_HATE"},"C":null,"R":{"char_id":"JOOSHIYOON_FENRIR_CA_NULL","face":"UNIT_LAUGH"}}}},{"id":"L9_1","type":"dialog","speaker":"SEO_YOON_ALT_CA_NULL","text":{"KOREA":"부상자 옆에서 엄살 피우기야, 선배?","JPN":"怪我人の前で大袈裟に言わないでよ、先輩！","ENG":"Are you seriously fussing over finger pain when you're standing next to an injured person?","TWN":"你這是在傷患旁邊裝可憐嗎，前輩？"},"stage":{"bg":"COUNTERSIDE_ASH","bgm":"BATTLE_BOSS_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SEO_YOON_ALT_CA_NULL","face":"UNIT_SERIOUS"},"C":null,"R":{"char_id":"JOOSHIYOON_FENRIR_CA_NULL","face":"UNIT_LAUGH"}}}},{"id":"L15_1","type":"dialog","speaker":"KNIGHT_NPC_CHIEF_NULL","text":{"KOREA":"나는 영광스러운 수도 방위 기사단! 7번대 대장 루지에!","JPN":"私は栄光ある首都防衛騎士団！　七番隊隊長ルージ！","ENG":"I am Rougié, the seventh captain of the Capital Defense Knights!","TWN":"我是榮耀的首都護衛騎士團第7小隊的隊長，盧吉爾！"},"stage":{"bg":"COUNTERSIDE_ASH","bgm":"BATTLE_BOSS_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"KNIGHT_NPC_CHIEF_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L16_1","type":"dialog","speaker":"KNIGHT_NPC_CHIEF_NULL","text":{"KOREA":"구원을 방해하겠다면 용서하지……","JPN":"救いの邪魔をする者は、許さ……","ENG":"Those who stand in the way of salvation will not be–","TWN":"如果你們想妨礙救贖，我是不會……"},"stage":{"bg":"COUNTERSIDE_ASH","bgm":"BATTLE_BOSS_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"KNIGHT_NPC_CHIEF_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L19_1","type":"dialog","speaker":"KNIGHT_NPC_CHIEF_NULL","text":{"KOREA":"우읏?!","JPN":"ううっ！？","ENG":"Uuuoh?!","TWN":"唔唔？！"},"stage":{"bg":"COUNTERSIDE_ASH","bgm":"BATTLE_BOSS_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":{"char_id":"KNIGHT_NPC_CHIEF_NULL","face":"UNIT_IDLE"}}}},{"id":"L20_1","type":"dialog","speaker":"YOOMINA_FENRIR_NEXT_NULL","text":{"KOREA":"저리 비켜!!","JPN":"どいてっ！！","ENG":"Out of the way!","TWN":"讓開！！"},"stage":{"bg":"COUNTERSIDE_ASH","bgm":"BATTLE_BOSS_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"YOOMINA_FENRIR_NEXT_NULL","face":"UNIT_SERIOUS"},"C":null,"R":{"char_id":"KNIGHT_NPC_CHIEF_NULL","face":"UNIT_IDLE"}}}},{"id":"L25_1","type":"dialog","speaker":"KNIGHT_NPC_CHIEF_NULL","text":{"KOREA":"크억……!","JPN":"くあっ……！","ENG":"Kuh...!","TWN":"咳呃……！"},"stage":{"bg":"COUNTERSIDE_ASH","bgm":"BATTLE_BOSS_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"KNIGHT_NPC_CHIEF_NULL","face":"UNIT_IDLE"},"R":{"char_id":"KNIGHT_NPC_NULL_NULL","face":"UNIT_IDLE"}}},"sfx":"FX_CUTSCEN_NOISE_RUSTLE_04"},{"id":"L26_1","type":"dialog","speaker":"KNIGHT_NPC_NULL_NULL","text":{"KOREA":"대장님!","JPN":"隊長！","ENG":"Captain!","TWN":"隊長！"},"stage":{"bg":"COUNTERSIDE_ASH","bgm":"BATTLE_BOSS_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"KNIGHT_NPC_CHIEF_NULL","face":"UNIT_IDLE"},"R":{"char_id":"KNIGHT_NPC_NULL_NULL","face":"UNIT_IDLE"}}},"sfx":"FX_COMBAT_ALL_FOOT_STEP_LANDING_SMALL_02"},{"id":"L27_1","type":"dialog","speaker":"KNIGHT_NPC_CHIEF_NULL","text":{"KOREA":"난 신경 쓰지 말고 싸워라……! 적은 고작 넷이다!","JPN":"私のことは気にせずに戦え……！　敵はたかだか四人だ！","ENG":"Keep fighting...! There are only four of them!","TWN":"別管我，繼續……戰鬥！敵人就只有四個人！"},"stage":{"bg":"COUNTERSIDE_ASH","bgm":"BATTLE_BOSS_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"KNIGHT_NPC_CHIEF_NULL","face":"UNIT_IDLE"},"R":{"char_id":"KNIGHT_NPC_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L28_1","type":"dialog","speaker":"KNIGHT_NPC_NULL_NULL","text":{"KOREA":"빌어먹을 이방인들……!","JPN":"クソッたれの異邦人ども……！","ENG":"Damned outsiders...!","TWN":"可惡的外邦人……！"},"stage":{"bg":"COUNTERSIDE_ASH","bgm":"BATTLE_BOSS_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"KNIGHT_NPC_NULL_NULL","face":"UNIT_IDLE"},"C":{"char_id":"KNIGHT_NPC_CHIEF_NULL","face":"UNIT_IDLE"},"R":null}},"sfx":"FX_COMBAT_ALL_FOOT_STEP_LANDING_SMALL"},{"id":"L29_1","type":"dialog","speaker":"KNIGHT_NPC_NULL_NULL","text":{"KOREA":"7번대 돌격! 우리도 대장님을 따라 끝까지 싸운다!","JPN":"七番隊突撃！　我々も隊長に従い、最後まで戦う！","ENG":"7th squad, charge! We will fight until the very end!","TWN":"第7小隊突擊！我們也要追隨隊長，和敵人奮戰到底！"},"stage":{"bg":"COUNTERSIDE_ASH","bgm":"BATTLE_BOSS_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"KNIGHT_NPC_NULL_NULL","face":"UNIT_IDLE"},"C":{"char_id":"KNIGHT_NPC_CHIEF_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L31_1","type":"dialog","speaker":"YOOMINA_FENRIR_NEXT_NULL","text":{"KOREA":"대체 뭐야? 자기들도 멸망하지 않으려고 그렇게 필사적이었으면서!","JPN":"いったい何なの？　自分たちだって滅亡から逃れるためにあれだけ必死だったくせに！","ENG":"What is this? They were so desperate to stop their world from getting destroyed!","TWN":"他們究竟怎麼回事？明明為了自己的世界不被毀滅而拼命過……"},"stage":{"bg":"COUNTERSIDE_ASH","bgm":"BATTLE_BOSS_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"YOOMINA_FENRIR_NEXT_NULL","face":"UNIT_HATE"},"R":null}}},{"id":"L32_1","type":"dialog","speaker":"YOOMINA_FENRIR_NEXT_NULL","text":{"KOREA":"왜 우리 세계를 멸망시키려고 야단인데! 그래 봤자 뭐가 바뀐다고!","JPN":"何でそこまで私たちの世界を滅ぼそうとするの！　それでいったい何が変わるのよ！","ENG":"Why are they so eager to destroy ours?! Nothing's gonna change!","TWN":"為什麼又要這麼急切地毀滅我們的世界呢！那樣能改變什麼！"},"stage":{"bg":"COUNTERSIDE_ASH","bgm":"BATTLE_BOSS_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"YOOMINA_FENRIR_NEXT_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L35_1","type":"dialog","speaker":"HILDE_FENRIR_NEXT_NULL","text":{"KOREA":"아니. 바뀐다.","JPN":"いや、変わる。","ENG":"Wrong. There will be change.","TWN":"不，能改變。"},"stage":{"bg":"COUNTERSIDE_ASH","bgm":"BATTLE_BOSS_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"HILDE_FENRIR_NEXT_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"JOOSHIYOON_FENRIR_CA_NULL","face":"UNIT_SURPRISE"}}}},{"id":"L37_1","type":"dialog","speaker":"YOOMINA_FENRIR_NEXT_NULL","text":{"KOREA":"뭐?","JPN":"え？","ENG":"What?","TWN":"什麼？"},"stage":{"bg":"COUNTERSIDE_ASH","bgm":"BATTLE_BOSS_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"YOOMINA_FENRIR_NEXT_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L40_1","type":"dialog","speaker":"HILDE_FENRIR_NEXT_NULL","text":{"KOREA":"클리포트 게임에서 승리한 마왕은 소원을 이룰 수 있으니까.","JPN":"クリフォトゲームで勝利した魔王は願いを叶えてもらえるんだ。","ENG":"The Demon Lord who wins the Qliphoth Game will be granted their wish.","TWN":"在逆卡巴拉遊戲中獲勝的魔王可以實現願望。"},"stage":{"bg":"COUNTERSIDE_ASH","bgm":"BATTLE_BOSS_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"HILDE_FENRIR_NEXT_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"JOOSHIYOON_FENRIR_CA_NULL","face":"UNIT_IDLE"}}}},{"id":"L41_1","type":"dialog","speaker":"JOOSHIYOON_FENRIR_CA_NULL","text":{"KOREA":"하하, 그거 재미있는 규칙이네요.","JPN":"はは、それは面白いルールですね。","ENG":"Ha ha, now that's an interesting rule.","TWN":"哈哈，這個規則很有意思啊。"},"stage":{"bg":"COUNTERSIDE_ASH","bgm":"BATTLE_BOSS_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"HILDE_FENRIR_NEXT_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"JOOSHIYOON_FENRIR_CA_NULL","face":"UNIT_LAUGH"}}}},{"id":"L42_1","type":"dialog","speaker":"JOOSHIYOON_FENRIR_CA_NULL","text":{"KOREA":"혹시 대균열에 램프의 요정이라도 잠들어 있는 건가요?","JPN":"ひょっとして大亀裂にはランプの妖精でも眠っているんでしょうか？","ENG":"Is there some sort of slumbering genie within the Grand Dimension Crevice?","TWN":"難道G1大峽谷裡還沉睡著神燈精靈嗎？"},"stage":{"bg":"COUNTERSIDE_ASH","bgm":"BATTLE_BOSS_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"HILDE_FENRIR_NEXT_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"JOOSHIYOON_FENRIR_CA_NULL","face":"UNIT_IDLE"}}}},{"id":"L43_1","type":"dialog","speaker":"HILDE_FENRIR_NEXT_NULL","text":{"KOREA":"그런 호구라면 차라리 다행이겠지.","JPN":"眠っているのが、そんなあほんだらならよかったんだがな。","ENG":"I wish it were someone that foolish.","TWN":"要是那麼簡單就好了。"},"stage":{"bg":"COUNTERSIDE_ASH","bgm":"BATTLE_BOSS_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"HILDE_FENRIR_NEXT_NULL","face":"UNIT_HATE"},"C":null,"R":{"char_id":"JOOSHIYOON_FENRIR_CA_NULL","face":"UNIT_IDLE"}}}},{"id":"L48_1","type":"dialog","speaker":"KNIGHT_NPC_NULL_NULL","text":{"KOREA":"크, 허억……!","JPN":"くっ、がはっ……！","ENG":"Gh, hah...","TWN":"咳，呵呃……！"},"stage":{"bg":"COUNTERSIDE_ASH","bgm":"BATTLE_BOSS_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"KNIGHT_NPC_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L50_1","type":"dialog","speaker":"SEO_YOON_ALT_CA_NULL","text":{"KOREA":"저쪽이야! 지평선이 보이기 시작했어!","JPN":"あそこよ！　地平線が見えた！","ENG":"There! I see the horizon!","TWN":"在那邊！看見盡頭了！"},"stage":{"bg":"COUNTERSIDE_ASH","bgm":"BATTLE_BOSS_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SEO_YOON_ALT_CA_NULL","face":"UNIT_SERIOUS"},"R":null}},"sfx":"FX_CUTSCEN_NOISE_RUSTLE_04"},{"id":"L3_1","type":"dialog","speaker":"JOOSHIYOON_FENRIR_CA_NULL","text":{"KOREA":"측면에서 환영객들도 몰려오는데요. 서두르지 않으면 다시 발목이 잡히겠어요.","JPN":"横からお迎えに来ている方々も見えますが、急がないとまた足止めを食らってしまいますね。","ENG":"We have incoming guests from the side. If we don't hurry, we'll get caught up.","TWN":"側面也有很多前來歡迎的人。不抓緊時間的話會再次被絆住手腳。"},"stage":{"bg":"COUNTERSIDE_ASH","bgm":"BATTLE_BOSS_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"HILDE_FENRIR_NEXT_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"JOOSHIYOON_FENRIR_CA_NULL","face":"UNIT_IDLE"}}}},{"id":"L6_1","type":"dialog","speaker":"YOOMINA_FENRIR_NEXT_NULL","text":{"KOREA":"이해가 안 돼. 그럼 그 소원 때문에 웃기지도 않는 규칙에 따른다는 거야?","JPN":"理解できない。じゃあその願いを叶えてもらうために、このふざけたルールに従っているっていうの？","ENG":"I don't understand. So they're following this ridiculous rule just for a wish?","TWN":"我不明白。就是因為那個願望，他們才遵守這種一點都不好玩的規則嗎？"},"stage":{"bg":"COUNTERSIDE_ASH","bgm":"BATTLE_BOSS_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"YOOMINA_FENRIR_NEXT_NULL","face":"UNIT_HATE"},"R":null}}},{"id":"L7_1","type":"dialog","speaker":"YOOMINA_FENRIR_NEXT_NULL","text":{"KOREA":"레이 선배는… 네헤모트는 강하잖아.","JPN":"レイ先輩は……ネヘモトは強いでしょ。","ENG":"Ray, I mean, Nehemoth is strong.","TWN":"雷伊前輩……貝赫莫特不是應該很強嗎？"},"stage":{"bg":"COUNTERSIDE_ASH","bgm":"BATTLE_BOSS_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"YOOMINA_FENRIR_NEXT_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L8_1","type":"dialog","speaker":"YOOMINA_FENRIR_NEXT_NULL","text":{"KOREA":"그런 힘을 가지고 있는 사람이 왜 소원에 매달리는 건데?","JPN":"そんな力を持っているのに、何をそんなに願いにすがる必要があるの？","ENG":"Why would someone with such power cling to a stupid wish?","TWN":"擁有那種力量的人為什麼還執著於一個願望呢？"},"stage":{"bg":"COUNTERSIDE_ASH","bgm":"BATTLE_BOSS_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"YOOMINA_FENRIR_NEXT_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L12_1","type":"dialog","speaker":"HILDE_FENRIR_NEXT_NULL","text":{"KOREA":"내가 알던 신입이 맞군. 여전히 어수룩해.","JPN":"相変わらずだな、新人。頭の中がお花畑だ。","ENG":"You haven't changed at all, rookie. Still naive.","TWN":"你還是那麼單純啊，新人。不管做什麼都是傻乎乎的。"},"stage":{"bg":"COUNTERSIDE_ASH","bgm":"BATTLE_BOSS_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"HILDE_FENRIR_NEXT_NULL","face":"UNIT_IDLE"},"C":null,"R":null}}},{"id":"L14_1","type":"dialog","speaker":"YOOMINA_FENRIR_NEXT_NULL","text":{"KOREA":"어, 어수룩하긴 누가…!","JPN":"だ、誰がお花畑よ……！","ENG":"N-naive?! Who are you calling naive...?!","TWN":"你，你說誰傻乎乎的……！"},"stage":{"bg":"COUNTERSIDE_ASH","bgm":"BATTLE_BOSS_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"HILDE_FENRIR_NEXT_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"YOOMINA_FENRIR_NEXT_NULL","face":"UNIT_SURPRISE"}}}},{"id":"L15_1","type":"dialog","speaker":"HILDE_FENRIR_NEXT_NULL","text":{"KOREA":"너는 어땠지? 그 코트를 손에 넣고 모든 일이 네가 원하던 대로 잘 풀렸나?","JPN":"お前はどうだった？　そのコートを手に入れて、すべてが望み通りにいくようになったか？","ENG":"What about you? Did everything work out the way you wanted it to be, wearing that coat of yours?","TWN":"那你呢？你手裡拿著那件大衣，所有事就會如你所願地順利解決嗎？"},"stage":{"bg":"COUNTERSIDE_ASH","bgm":"BATTLE_BOSS_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"HILDE_FENRIR_NEXT_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"YOOMINA_FENRIR_NEXT_NULL","face":"UNIT_SURPRISE"}}}},{"id":"L16_1","type":"dialog","speaker":"YOOMINA_FENRIR_NEXT_NULL","text":{"KOREA":"그건……. 그렇지는 않았지만…….","JPN":"それは……そうじゃないけど……","ENG":"That’s... No, but...","TWN":"這……我不是那個意思……"},"stage":{"bg":"COUNTERSIDE_ASH","bgm":"BATTLE_BOSS_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"HILDE_FENRIR_NEXT_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"YOOMINA_FENRIR_NEXT_NULL","face":"UNIT_DESPAIR"}}}},{"id":"L19_1","type":"dialog","speaker":"HILDE_FENRIR_NEXT_NULL","text":{"KOREA":"명심해라. 창칼로 해결되는 문제만큼─","JPN":"肝に銘じておけ。武力で解決できる問題ほど─","ENG":"Remember. There's nothing easier─","TWN":"記住了，只要能用刀劍來解決的問題——"},"stage":{"bg":"COUNTERSIDE_ASH","bgm":"BATTLE_BOSS_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"HILDE_FENRIR_NEXT_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L25_1","type":"dialog","speaker":"HILDE_FENRIR_NEXT_NULL","text":{"KOREA":"─쉬운 문제도 없다는 걸.","JPN":"─簡単なものはないということをな。","ENG":"─than a problem that can be solved by brute force.","TWN":"——就都不是問題。"},"stage":{"bg":"COUNTERSIDE_ASH","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"HILDE_FENRIR_NEXT_NULL","face":"UNIT_HATE"},"R":null}}},{"id":"L28_1","type":"dialog","speaker":"SEO_YOON_ALT_CA_NULL","text":{"KOREA":"저 참격은……?","JPN":"あの斬撃は……？","ENG":"That attack...","TWN":"剛剛的攻擊是……？"},"stage":{"bg":"COUNTERSIDE_ASH","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"JOOSHIYOON_FENRIR_CA_NULL","face":"UNIT_SURPRISE"},"C":null,"R":{"char_id":"SEO_YOON_ALT_CA_NULL","face":"UNIT_SURPRISE"}}}},{"id":"L29_1","type":"dialog","speaker":"JOOSHIYOON_FENRIR_CA_NULL","text":{"KOREA":"어이쿠, 저희가 인사하러 가지 않아서 토라지셨나 보네요.","JPN":"あちゃ～、僕たちが挨拶に行かなかったから怒ってるみたいですね。","ENG":"My, my. You must have been upset that we didn't come out to greet you.","TWN":"哎呀呀，看來是我們沒去打招呼，所以耍脾氣了啊。"},"stage":{"bg":"COUNTERSIDE_ASH","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"JOOSHIYOON_FENRIR_CA_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"SEO_YOON_ALT_CA_NULL","face":"UNIT_SURPRISE"}}}},{"id":"L30_1","type":"dialog","speaker":"JOOSHIYOON_FENRIR_CA_NULL","text":{"KOREA":"무서운 숙녀 분들께 시달리시고도 정정하시군요. 감탄했습니다, 전하.","JPN":"恐ろしいお嬢さんたちのせいで苦労されているのに、お元気そうで感服しました、殿下。","ENG":"I'm impressed, Your Highness. You're still intact after dealing with those daunting ladies.","TWN":"應付完二位可怕的淑女後還能像沒事一般，我深感佩服，殿下。"},"stage":{"bg":"COUNTERSIDE_ASH","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"JOOSHIYOON_FENRIR_CA_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"SEO_YOON_ALT_CA_NULL","face":"UNIT_SURPRISE"}}}},{"id":"L32_1","type":"dialog","speaker":"PRINCE_KNIGHT_NULL_NULL","text":{"KOREA":"짐승만도 못한 괴물들을 숙녀 취급해 주는 건가.","JPN":"獣以下の怪物たちをお嬢さんと呼んでくれるのか。","ENG":"You consider those monsters as ladies, hmm?","TWN":"你把那種連畜生都不如的怪物稱為淑女嗎？"},"stage":{"bg":"COUNTERSIDE_ASH","bgm":"BATTLE_BOSS_04","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"PRINCE_KNIGHT_NULL_NULL","face":"UNIT_PRIDE"},"R":null}},"sfx":"FX_COMBAT_ALL_FOOT_STEP_LANDING_SMALL_02"},{"id":"L33_1","type":"dialog","speaker":"PRINCE_KNIGHT_NULL_NULL","text":{"KOREA":"재밌군, 소년. 그 대범함만큼은 확실히 구도자를 닮았어.","JPN":"面白いな、少年。その大胆さは確かに求道者に近いものがある。","ENG":"Interesting, boy. Your boldness does resemble the Seeker of Truth after all.","TWN":"真有意思，年輕人。你的從容之姿確實很有求道者的風範。"},"stage":{"bg":"COUNTERSIDE_ASH","bgm":"BATTLE_BOSS_04","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"PRINCE_KNIGHT_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L35_1","type":"dialog","speaker":"YOOMINA_FENRIR_NEXT_NULL","text":{"KOREA":"제길, 거의 다 왔었는데…….","JPN":"くそ、あともう少しだったのに……","ENG":"Tsk, we are almost there...","TWN":"可惡，差不多都快到了……"},"stage":{"bg":"COUNTERSIDE_ASH","bgm":"BATTLE_BOSS_04","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"YOOMINA_FENRIR_NEXT_NULL","face":"UNIT_HATE"},"R":null}}},{"id":"L38_1","type":"dialog","speaker":"PRINCE_KNIGHT_NULL_NULL","text":{"KOREA":"다 왔다고?","JPN":"もう少しだと？","ENG":"Almost there?","TWN":"都快到了？"},"stage":{"bg":"COUNTERSIDE_ASH","bgm":"BATTLE_BOSS_04","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"PRINCE_KNIGHT_NULL_NULL","face":"UNIT_PRIDE"},"R":null}}},{"id":"L39_1","type":"dialog","speaker":"PRINCE_KNIGHT_NULL_NULL","text":{"KOREA":"이런, 저주받은 늑대여. 갑자기 광대가 되겠다는 결심이라도 섰나?","JPN":"呪われた狼よ。いきなりピエロにでもなりたくなったのか？","ENG":"My dear Cursed Wolf. Did you decide to become a jester?","TWN":"呵，受詛咒的狼，你這是在扮演什麼小丑嗎？"},"stage":{"bg":"COUNTERSIDE_ASH","bgm":"BATTLE_BOSS_04","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"PRINCE_KNIGHT_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L40_1","type":"dialog","speaker":"PRINCE_KNIGHT_NULL_NULL","text":{"KOREA":"상황이 제대로 파악되지 않은 모양이니 내 친히 가르쳐 주지.","JPN":"まだ状況がきちんと把握できてないようだから、特別に教えてやろう。","ENG":"Since you still haven't an idea on what's going on, let me kindly teach you.","TWN":"你好像還沒弄清楚狀況，那我就親自告訴你吧。"},"stage":{"bg":"COUNTERSIDE_ASH","bgm":"BATTLE_BOSS_04","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"PRINCE_KNIGHT_NULL_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L41_1","type":"dialog","speaker":"PRINCE_KNIGHT_NULL_NULL","text":{"KOREA":"내가 살아 있는 한, 너희는 아직 한 발짝도 나아가지 못한 것이다.","JPN":"私が生きている限り、貴様たちの状況はまだ一歩も前進できていないのだ。","ENG":"You will never make any progress as long as I am alive.","TWN":"只要我活著，你們就休想從這裡邁出一步。"},"stage":{"bg":"COUNTERSIDE_ASH","bgm":"BATTLE_BOSS_04","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"PRINCE_KNIGHT_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}}]`);export{e as default};